const Quill = require('quill');

// Function to convert Delta JSON to HTML
function deltaToHtml(deltaJson) {
    const quill = new Quill(document.createElement('div'));
    quill.setContents(deltaJson);
    return quill.root.innerHTML;
}

// Example usage
const deltaJson = {
    ops: [
        { insert: "Hello, " },
        { insert: "world!", attributes: { bold: true } },
        { insert: "\n" }
    ]
};

const html = deltaToHtml(deltaJson);
console.log(html);